const urlString = $.input.videoUrls || '';
const urls = urlString.split(',').map(u => u.trim()).filter(u => u.length > 0 && u.includes('youtube') || u.includes('youtu.be'));
return { urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapeVideos.response.iterations || [];
let compiled = '';
let successCount = 0;

iterations.forEach((iter, i) => {
  const url = urls[i] || '';
  const data = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;
  compiled += '=== VIDEO ' + (i + 1) + ' ===\n';
  compiled += 'URL: ' + url + '\n';
  if (data && data.markdown) {
    compiled += data.markdown.slice(0, 3000) + '\n';
    successCount++;
  } else {
    compiled += 'Failed to scrape\n';
  }
  compiled += '\n';
});

return { compiled: compiled.slice(0, 25000), successCount, totalVideos: urls.length };

const d = $.steps.compileVideoData.output;
const platforms = $.input.targetPlatforms || 'YouTube Shorts, TikTok, Instagram Reels';

let prompt = 'You are a video content repurposing strategist. Analyze the following YouTube video pages and create a detailed plan for converting them into short-form content.\n\n';
prompt += 'TARGET PLATFORMS: ' + platforms + '\n';
prompt += 'VIDEOS ANALYZED: ' + d.successCount + ' of ' + d.totalVideos + '\n\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- For each video, identify 3-5 clip-worthy moments based on the content\n';
prompt += '- Suggest optimal clip length (15s, 30s, 60s) for each platform\n';
prompt += '- Write a catchy hook/caption for each suggested clip\n';
prompt += '- Recommend hashtags and posting strategy per platform\n';
prompt += '- Score each clip idea for viral potential (1-10)\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "videos": [\n';
prompt += '    {\n';
prompt += '      "originalUrl": "url",\n';
prompt += '      "videoTitle": "inferred title",\n';
prompt += '      "clips": [\n';
prompt += '        {\n';
prompt += '          "clipIdea": "description of the clip moment",\n';
prompt += '          "hook": "attention-grabbing first line",\n';
prompt += '          "caption": "full caption for posting",\n';
prompt += '          "duration": "30s",\n';
prompt += '          "platform": "YouTube Shorts",\n';
prompt += '          "hashtags": ["tag1"],\n';
prompt += '          "viralScore": 8\n';
prompt += '        }\n';
prompt += '      ]\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalClipsPlanned": 0,\n';
prompt += '  "postingStrategy": "recommended posting cadence",\n';
prompt += '  "topPicks": ["best clip ideas across all videos"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { videos: [], totalClipsPlanned: 0, postingStrategy: raw, topPicks: [] }; }

const ai = $.steps.parseAI.output;
const today = new Date().toISOString().slice(0, 10);
const rows = [];
rows.push(['Date', 'Original Video', 'Clip Idea', 'Hook', 'Caption', 'Duration', 'Platform', 'Hashtags', 'Viral Score', 'Status']);
(ai.videos || []).forEach(v => {
  (v.clips || []).forEach(c => {
    rows.push([today, v.videoTitle || '', c.clipIdea || '', c.hook || '', (c.caption || '').slice(0, 500), c.duration || '', c.platform || '', (c.hashtags || []).join(', '), String(c.viralScore || ''), 'Planned']);
  });
});
return { rows, clipCount: rows.length - 1 };

const ai = $.steps.parseAI.output;
const clips = $.steps.buildSheetRows.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Video Repurposing Plan', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Videos Analyzed:* ' + (ai.videos || []).length + ' | *Clips Planned:* ' + clips.clipCount } });
blocks.push({ type: 'divider' });

if (ai.topPicks && ai.topPicks.length > 0) {
  let pickText = '*Top Clip Ideas:*\n';
  ai.topPicks.slice(0, 5).forEach((p, i) => { pickText += ':star: ' + (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: pickText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

(ai.videos || []).slice(0, 3).forEach(v => {
  let text = '*' + (v.videoTitle || 'Video') + '*\n';
  (v.clips || []).slice(0, 3).forEach(c => {
    const icon = (c.viralScore || 0) >= 8 ? ':fire:' : ':chart_with_upwards_trend:';
    text += icon + ' ' + c.clipIdea + ' (' + c.duration + ', ' + c.platform + ')\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

if (ai.postingStrategy) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Posting Strategy:* ' + ai.postingStrategy.slice(0, 500) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Plan saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallback = 'Video Repurposing: ' + clips.clipCount + ' clips planned from ' + (ai.videos || []).length + ' videos';
return { blocks, fallback };
